python3 - <<'EOF'
import pycdlib,io
iso=pycdlib.PyCdlib(); iso.open('/app/alpine.iso')
files=[]
def walk(p='/'):
    for child in iso.list_children(iso_path=p):
        n=child.file_identifier().decode()
        if n in ('.','..'): continue
        full=(p.rstrip('/')+'/'+n)
        if child.is_dir(): walk(full)
        else: files.append(full)
walk()
for f in files:
    if 'syslinux' in f.lower() or f.lower().endswith('.cfg') or 'grub' in f.lower():
        print(f)
print('---total',len(files))
EOF
